module top_module(
  input         clock, reset, 
  output [3:0]  count
);reg [3:0] counter;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clock or posedge dbg_halt) begin
    if (reset) begin
      counter <= 4'b0;
    end else begin
      counter <= counter + 1;
    end
  end

  assign count = counter;

endmodule
